            cmp_function,
            free_function,
        }
    }

    pub fn bostree_node_count(&self) -> u32 {
        match &self.root_node {
            Some(root) => {
                let r = root.borrow();
                r.left_child_count + r.right_child_count + 1
            }
            None => 0,
        }
    }

    pub fn bostree_insert(&mut self, key: String, data: Option<String>) -> Rc<RefCell<BOSNode>> {
        let mut parent: Option<Rc<RefCell<BOSNode>>> = None;
        let mut node_opt = self.root_node.clone();
        let mut came_from_left = false; // to know which child pointer to update

        // Find insertion point
        while let Some(current) = node_opt.clone() {
            parent = Some(current.clone());
            let cmp = {
                let current_ref = current.borrow();
                (self.cmp_function)(&key, &current_ref.key)
            };
            if cmp < 0 {
                {
                    let mut current_ref = current.borrow_mut();
                    current_ref.left_child_count += 1;
                }
                let next = current.borrow().left_child_node.clone();
                node_opt = next;
                came_from_left = true;
            } else {
                // cmp >= 0, go right
                {
                    let mut current_ref = current.borrow_mut();
                    current_ref.right_child_count += 1;
                }
                let next = current.borrow().right_child_node.clone();
                node_opt = next;
                came_from_left = false;
            }
        }

        // Create new node
        let new_node = Rc::new(RefCell::new(BOSNode {
            left_child_count: 0,
            right_child_count: 0,
            depth: 0,
            left_child_node: None,
            right_child_node: None,
            parent_node: None,
            key: key.clone(),
            data,
            weak_ref_count: 1,
            weak_ref_node_valid: 1,
        }));

        // Set parent link
        if let Some(ref p) = parent {
            new_node.borrow_mut().parent_node = Some(Rc::downgrade(p));
            if came_from_left {
                p.borrow_mut().left_child_node = Some(new_node.clone());
            } else {
                p.borrow_mut().right_child_node = Some(new_node.clone());
            }

