use std::cell::RefCell;
use std::cmp::max;
use std::rc::{Rc, Weak};

#[derive(Debug)]
pub struct BOSTree {
    /// The root node of the tree.
    pub root_node: Option<Rc<RefCell<BOSNode>>>,
    /// The key comparison function.
    pub cmp_function: BOSTreeCmpFunction,
    /// The optional free function for node data.
    pub free_function: Option<BOSTreeFreeFunction>,
}

/// The node structure.
#[derive(Debug)]
pub struct BOSNode {
    /// Number of nodes in the left subtree.
    pub left_child_count: u32,
    /// Number of nodes in the right subtree.
    pub right_child_count: u32,
    /// Cached depth of the node.
    pub depth: u32,
    /// Left child node.
    pub left_child_node: Option<Rc<RefCell<BOSNode>>>,
    /// Right child node.
    pub right_child_node: Option<Rc<RefCell<BOSNode>>>,
    /// Parent node (using a weak reference to avoid cycles).
    pub parent_node: Option<Weak<RefCell<BOSNode>>>,
    /// The key for this node.
    pub key: String,
    /// The associated data.
    pub data: Option<String>,
    /// Internal weak reference counter.
    pub weak_ref_count: u8,
    /// Validity flag for the weak reference.
    pub weak_ref_node_valid: u8,
}

/// Type alias for a key comparison function.
/// Should return a positive value if `b` is larger than `a`,
/// a negative value if `a` is larger, and zero if equal.
pub type BOSTreeCmpFunction = fn(&str, &str) -> i32;

/// Type alias for a free function which will be called on nodes
/// that are removed.
pub type BOSTreeFreeFunction = fn(&Rc<RefCell<BOSNode>>);

/// Calculate balance factor: right depth - left depth
fn balance(node: &BOSNode) -> i32 {
    let left_depth = node.left_child_node.as_ref().map_or(0, |n| n.borrow().depth as i32 + 1);
    let right_depth = node.right_child_node.as_ref().map_or(0, |n| n.borrow().depth as i32 + 1);
    right_depth - left_depth
}

/// Update depth of a node based on its children
fn update_depth(node: &mut BOSNode) {
    let left_depth = node.left_child_node.as_ref().map_or(0, |n| n.borrow().depth + 1);
    let right_depth = node.right_child_node.as_ref().map_or(0, |n| n.borrow().depth + 1);
    node.depth = max(left_depth, right_depth);
}

/// Perform a right rotation
fn rotate_right(tree: &mut BOSTree, p: Rc<RefCell<BOSNode>>) -> Rc<RefCell<BOSNode>> {
    // P becomes right child of L
    let l = p.borrow().left_child_node.clone().expect("rotate_right requires left child");

    // Fix parent's pointer to P (or root)
    let parent_weak = p.borrow().parent_node.clone();
    if let Some(parent_weak_inner) = &parent_weak {
        if let Some(parent) = parent_weak_inner.upgrade() {
            let parent_left = parent.borrow().left_child_node.clone();
            if let Some(ref left) = parent_left {
                if Rc::ptr_eq(left, &p) {
                    parent.borrow_mut().left_child_node = Some(l.clone());
                } else {
                    parent.borrow_mut().right_child_node = Some(l.clone());
                }
            } else {
                parent.borrow_mut().right_child_node = Some(l.clone());
            }
        }
    } else {
        tree.root_node = Some(l.clone());
    }

    // Update parent pointers
    l.borrow_mut().parent_node = parent_weak;

    // Move L's right child to P's left
    let l_right = l.borrow().right_child_node.clone();
    p.borrow_mut().left_child_node = l_right.clone();
    p.borrow_mut().left_child_count = l.borrow().right_child_count;
    if let Some(ref lr) = l_right {
        lr.borrow_mut().parent_node = Some(Rc::downgrade(&p));
    }

    // Update P's depth
    update_depth(&mut p.borrow_mut());
    p.borrow_mut().parent_node = Some(Rc::downgrade(&l));

    // Set L's right child to P
    l.borrow_mut().right_child_node = Some(p.clone());
    let p_borrow = p.borrow();
    let right_count = p_borrow.right_child_count;
    let left_count = p_borrow.left_child_count;
    drop(p_borrow);
    l.borrow_mut().right_child_count = left_count + right_count + 1;
    update_depth(&mut l.borrow_mut());

    l
}

/// Perform a left rotation
fn rotate_left(tree: &mut BOSTree, p: Rc<RefCell<BOSNode>>) -> Rc<RefCell<BOSNode>> {
    // P becomes left child of R
