            p_mut.right_child_node = r_left.clone();
            p_mut.right_child_count = r_left_count;
            if let Some(ref child) = p_mut.right_child_node {
                child.borrow_mut().parent_node = Some(Rc::downgrade(p));
            }
            let ld = p_mut.left_child_node.as_ref().map_or(0, |n| n.borrow().depth + 1);
            let rd = p_mut.right_child_node.as_ref().map_or(0, |n| n.borrow().depth + 1);
