            if let Some(parent) = parent_weak.upgrade() {
                let mut parent_mut = parent.borrow_mut();
                if parent_mut.left_child_node.as_ref().map_or(false, |n| Rc::ptr_eq(n, p)) {
                    parent_mut.left_child_node = Some(r.clone());
                } else {
                    parent_mut.right_child_node = Some(r.clone());
                }
            }
        } else {
            self.root_node = Some(r.clone());
        }

        r.borrow_mut().parent_node = p_parent;

        {
            let mut p_mut = p.borrow_mut();
            p_mut.right_child_node = r_left.clone();
            p_mut.right_child_count = r_left_count;
            if let Some(ref child) = p_mut.right_child_node {
                child.borrow_mut().parent_node = Some(Rc::downgrade(p));
            }
            let ld = p_mut.left_child_node.as_ref().map_or(0, |n| n.borrow().depth + 1);
            let rd = p_mut.right_child_node.as_ref().map_or(0, |n| n.borrow().depth + 1);
            p_mut.depth = Self::imax(ld, rd);
            p_mut.parent_node = Some(Rc::downgrade(&r));
        }

        {
            let mut r_mut = r.borrow_mut();
            r_mut.left_child_node = Some(p.clone());
            let p_borrow = p.borrow();
            r_mut.left_child_count = p_borrow.left_child_count + p_borrow.right_child_count + 1;
            let ld = r_mut.left_child_node.as_ref().map_or(0, |n| n.borrow().depth + 1);
            let rd = r_mut.right_child_node.as_ref().map_or(0, |n| n.borrow().depth + 1);
            r_mut.depth = Self::imax(ld, rd);
        }

        r
    }

    pub fn bostree_new(
        cmp_function: BOSTreeCmpFunction,
        free_function: Option<BOSTreeFreeFunction>,
    ) -> Self {
        BOSTree {
            root_node: None,
            cmp_function,
            free_function,
        }
    }

    pub fn bostree_node_count(&self) -> u32 {
        match &self.root_node {
            Some(root) => {
                let root = root.borrow();
                root.left_child_count + root.right_child_count + 1
            }
            None => 0,
        }
    }

    pub fn bostree_insert(&mut self, key: String, data: Option<String>) -> Rc<RefCell<BOSNode>> {
        let mut node_ptr: Option<Rc<RefCell<BOSNode>>> = self.root_node.clone();
        let mut parent_node: Option<Rc<RefCell<BOSNode>>> = None;

        while let Some(ref current) = node_ptr {
            parent_node = Some(current.clone());
            let cmp = {
                let cur_borrow = current.borrow();
                (self.cmp_function)(&key, &cur_borrow.key)
            };
            if cmp < 0 {
                current.borrow_mut().left_child_count += 1;
                let next = current.borrow().left_child_node.clone();
                node_ptr = next;
            } else {
                current.borrow_mut().right_child_count += 1;
                let next = current.borrow().right_child_node.clone();
                node_ptr = next;
            }
        }

        let new_node = Rc::new(RefCell::new(BOSNode {
            left_child_count: 0,
            right_child_count: 0,
            depth: 0,
            left_child_node: None,
            right_child_node: None,
            parent_node: parent_node.as_ref().map(|p| Rc::downgrade(p)),
            key,
            data,
            weak_ref_count: 1,
            weak_ref_node_valid: 1,
        }));

        if let Some(ref parent) = parent_node {
            let mut parent_mut = parent.borrow_mut();
            let cmp = (self.cmp_function)(&new_node.borrow().key, &parent_mut.key);
            if cmp < 0 {
                parent_mut.left_child_node = Some(new_node.clone());
            } else {
                parent_mut.right_child_node = Some(new_node.clone());
            }
        } else {
            self.root_node = Some(new_node.clone());
            return new_node;
        }

        let parent = parent_node.unwrap();
        let depth_changed = {
            let par = parent.borrow();
            let left_ex = par.left_child_node.is_some();
            let right_ex = par.right_child_node.is_some();
            left_ex ^ right_ex
        };
        if depth_changed {
            parent.borrow_mut().depth += 1;
            let mut current = parent.clone();
            loop {
                let cp_opt = {
                    let cur_borrow = current.borrow();
                    cur_borrow.parent_node.as_ref().and_then(|w| w.upgrade())
                };
                if let Some(cp) = cp_opt {
                    let (new_left_depth, new_right_depth) = {
                        let cp_borrow = cp.borrow();
                        let ld = cp_borrow.left_child_node.as_ref().map_or(0, |n| n.borrow().depth + 1);
                        let rd = cp_borrow.right_child_node.as_ref().map_or(0, |n| n.borrow().depth + 1);
                        (ld, rd)
                    };
                    let max_depth = Self::imax(new_left_depth, new_right_depth);
                    {
                        let mut cp_mut = cp.borrow_mut();
                        if cp_mut.depth != max_depth {
                            cp_mut.depth = max_depth;
                        } else {
                            break;
                        }
                    }
                    if new_left_depth.wrapping_sub(2) == new_right_depth {
                        let left_balance = {
                            let cp_borrow = cp.borrow();
                            let left = cp_borrow.left_child_node.as_ref().unwrap();
                            Self::balance(&*left.borrow())
                        };
                        if left_balance > 0 {
                            let left_child = cp.borrow().left_child_node.clone().unwrap();
                            self.rotate_left(&left_child);
                        }
                        current = self.rotate_right(&cp);
                    } else if new_right_depth.wrapping_sub(2) == new_left_depth {
                        let right_balance = {
                            let cp_borrow = cp.borrow();
                            let right = cp_borrow.right_child_node.as_ref().unwrap();
                            Self::balance(&*right.borrow())
                        };
                        if right_balance < 0 {
                            let right_child = cp.borrow().right_child_node.clone().unwrap();
                            self.rotate_right(&right_child);
                        }
                        current = self.rotate_left(&cp);
                    } else {
                        current = cp.clone();
                    }
                } else {
                    break;
                }
            }
        }

        new_node
    }

    pub fn bostree_remove(&mut self, node: &Rc<RefCell<BOSNode>>) {
        if node.borrow().left_child_node.is_some() && node.borrow().right_child_node.is_some() {
            let successor = {
                let mut succ = node.borrow().right_child_node.clone().unwrap();
                loop {
                    let next = succ.borrow().left_child_node.clone();
                    if let Some(n) = next {
                        succ = n;
                    } else {
                        break;
                    }
                }
                succ
            };

            {
                let mut cur = node.borrow().right_child_node.clone().unwrap();
                while !Rc::ptr_eq(&cur, &successor) {
                    cur.borrow_mut().left_child_count -= 1;
                    let next = cur.borrow().left_child_node.clone().unwrap();
                    cur = next;
                }
            }

            {
                let succ_borrow = successor.borrow();
                let ld = succ_borrow.left_child_node.as_ref().map_or(0, |n| n.borrow().depth + 1);
                let rd = succ_borrow.right_child_node.as_ref().map_or(0, |n| n.borrow().depth + 1);
                drop(succ_borrow);
                successor.borrow_mut().depth = Self::imax(ld, rd);
            }

            let bubble_up = {
                let succ_borrow = successor.borrow();
                succ_borrow.parent_node.as_ref().and_then(|w| w.upgrade())
            };

            if let Some(ref bp) = bubble_up {
                let mut bp_mut = bp.borrow_mut();
                if bp_mut.left_child_node.as_ref().map_or(false, |n| Rc::ptr_eq(n, &successor)) {
                    bp_mut.left_child_count -= 1;
                } else {
                    bp_mut.right_child_count -= 1;
                }
            }

            {
                let mut node_mut = node.borrow_mut();
                let mut succ_mut = successor.borrow_mut();

                succ_mut.left_child_count = node_mut.left_child_count;
                succ_mut.right_child_count = node_mut.right_child_count;
                succ_mut.depth = node_mut.depth;

                if let Some(ref parent_weak) = node_mut.parent_node {
                    if let Some(parent) = parent_weak.upgrade() {
                        let mut parent_mut = parent.borrow_mut();
                        if parent_mut.left_child_node.as_ref().map_or(false, |n| Rc::ptr_eq(n, node)) {
                            parent_mut.left_child_node = Some(successor.clone());
                        } else {
                            parent_mut.right_child_node = Some(successor.clone());
                        }
                    }
                } else {
                    self.root_node = Some(successor.clone());
                }
                succ_mut.parent_node = node_mut.parent_node.clone();

                succ_mut.left_child_node = node_mut.left_child_node.clone();
                if let Some(ref left) = succ_mut.left_child_node {
                    left.borrow_mut().parent_node = Some(Rc::downgrade(&successor));
                }

                if !node_mut.right_child_node.as_ref().map_or(false, |n| Rc::ptr_eq(n, &successor)) {
                    succ_mut.right_child_node = node_mut.right_child_node.clone();
                    if let Some(ref right) = succ_mut.right_child_node {
                        right.borrow_mut().parent_node = Some(Rc::downgrade(&successor));
                    }
                }
            }

            self.rebalance_after_remove(bubble_up);
        } else {
            if node.borrow().parent_node.is_none() {
                if let Some(ref left) = node.borrow().left_child_node {
                    self.root_node = Some(left.clone());
                    left.borrow_mut().parent_node = None;
                } else if let Some(ref right) = node.borrow().right_child_node {
                    self.root_node = Some(right.clone());
                    right.borrow_mut().parent_node = None;
                } else {
                    self.root_node = None;
                }
            } else {
                let candidate = node.borrow().left_child_node.clone();
                let candidate_count = node.borrow().left_child_count;
                let (candidate, candidate_count) = if let Some(ref right) = node.borrow().right_child_node {
                    (Some(right.clone()), node.borrow().right_child_count)
                } else {
                    (candidate, candidate_count)
                };

                let parent = node.borrow().parent_node.as_ref().unwrap().upgrade().unwrap();
                {
                    let mut parent_mut = parent.borrow_mut();
                    if parent_mut.left_child_node.as_ref().map_or(false, |n| Rc::ptr_eq(n, node)) {
                        parent_mut.left_child_node = candidate.clone();
                        parent_mut.left_child_count = candidate_count;
                    } else {
                        parent_mut.right_child_node = candidate.clone();
                        parent_mut.right_child_count = candidate_count;
                    }
                }
                if let Some(ref cand) = candidate {
                    cand.borrow_mut().parent_node = Some(Rc::downgrade(&parent));
                }

                self.rebalance_after_remove(Some(parent));
            }
        }

        node.borrow_mut().weak_ref_node_valid = 0;
        self.do_weak_unref(node);
    }

    fn rebalance_after_remove(&mut self, mut bubble_up: Option<Rc<RefCell<BOSNode>>>) {
        let mut bubbling_finished = false;
        while let Some(ref bp) = bubble_up {
            if !bubbling_finished {
                let (left_depth, right_depth) = {
                    let bp_borrow = bp.borrow();
                    let ld = bp_borrow.left_child_node.as_ref().map_or(0, |n| n.borrow().depth + 1);
                    let rd = bp_borrow.right_child_node.as_ref().map_or(0, |n| n.borrow().depth + 1);
                    (ld, rd)
                };
                let new_depth = Self::imax(left_depth, right_depth);
                let depth_changed = {
                    let mut bp_mut = bp.borrow_mut();
                    let changed = bp_mut.depth != new_depth;
                    bp_mut.depth = new_depth;
                    changed
                };

                let balance = (right_depth as i32) - (left_depth as i32);

                if balance < -1 {
                    let left_child = bp.borrow().left_child_node.clone().unwrap();
                    let left_balance = {
                        let left_borrow = left_child.borrow();
                        Self::balance(&*left_borrow)
                    };
                    if left_balance > 0 {
                        self.rotate_left(&left_child);
                    }
                    let new_bp = self.rotate_right(bp);
                    bubble_up = Some(new_bp);
                } else if balance > 1 {
                    let right_child = bp.borrow().right_child_node.clone().unwrap();
                    let right_balance = {
                        let right_borrow = right_child.borrow();
                        Self::balance(&*right_borrow)
                    };
                    if right_balance < 0 {
                        self.rotate_right(&right_child);
                    }
                    let new_bp = self.rotate_left(bp);
                    bubble_up = Some(new_bp);
                } else {
                    if !depth_changed {
                        bubbling_finished = true;
                    }
                }
            }

            if let Some(parent) = {
                let bp_borrow = bp.borrow();
                bp_borrow.parent_node.as_ref().and_then(|w| w.upgrade())
            } {
                let mut parent_mut = parent.borrow_mut();
                if parent_mut.left_child_node.as_ref().map_or(false, |n| Rc::ptr_eq(n, bp)) {
                    parent_mut.left_child_count -= 1;
                } else {
                    parent_mut.right_child_count -= 1;
                }
                bubble_up = Some(parent);
            } else {
                bubble_up = None;
            }
        }
    }

    fn do_weak_unref(&mut self, node: &Rc<RefCell<BOSNode>>) {
        let mut node_mut = node.borrow_mut();
        node_mut.weak_ref_count -= 1;
        if node_mut.weak_ref_count == 0 {
            if let Some(ref free_func) = self.free_function {
                free_func(node);
            }
        }
    }

    pub fn bostree_node_weak_unref(
        &mut self,
        node: &Rc<RefCell<BOSNode>>,
    ) -> Option<Rc<RefCell<BOSNode>>> {
        let mut node_mut = node.borrow_mut();
        node_mut.weak_ref_count -= 1;
        if node_mut.weak_ref_count == 0 {
            if let Some(ref free_func) = self.free_function {
                free_func(node);
            }
            None
        } else {
            if node_mut.weak_ref_node_valid != 0 {
                Some(node.clone())
            } else {
                None
            }
        }
    }

    pub fn bostree_lookup(&self, key: &str) -> Option<Rc<RefCell<BOSNode>>> {
        let mut node = self.root_node.clone();
        while let Some(current) = node {
            let cmp = {
                let cur_borrow = current.borrow();
                (self.cmp_function)(key, &cur_borrow.key)
            };
            if cmp == 0 {
                return Some(current);
            } else if cmp < 0 {
                let next = current.borrow().left_child_node.clone();
                node = next;
            } else {
                let next = current.borrow().right_child_node.clone();
                node = next;
            }
        }
        None
    }

    pub fn bostree_select(&self, mut index: u32) -> Option<Rc<RefCell<BOSNode>>> {
        let mut node = self.root_node.clone();
        while let Some(current) = node {
            let left_count = current.borrow().left_child_count;
            if left_count <= index {
                index -= left_count;
                if index == 0 {
                    return Some(current);
                }
                index -= 1;
                let next = current.borrow().right_child_node.clone();
                node = next;
            } else {
                let next = current.borrow().left_child_node.clone();
                node = next;
            }
        }
        None
    }

    #[cfg(debug_assertions)]
    pub fn bostree_print(&self) {
        fn print_helper(node: &Rc<RefCell<BOSNode>>) {
            let node_borrow = node.borrow();
            println!(
                \"  {} [label=\\\"\\\\N ({},{},{})\\\"];\",
                node_borrow.key,
                node_borrow.left_child_count,
                node_borrow.right_child_count,
                node_borrow.depth
            );
            if let Some(ref parent_weak) = node_borrow.parent_node {
                if let Some(parent) = parent_weak.upgrade() {
                    println!(
                        \"  {} -> {} [color=green];\",
                        node_borrow.key,
                        parent.borrow().key
                    );
                }
            }
            if let Some(ref left) = node_borrow.left_child_node {
                println!(\"  {} -> {}\", node_borrow.key, left.borrow().key);
                print_helper(left);
            }
            if let Some(ref right) = node_borrow.right_child_node {
                println!(\"  {} -> {}\", node_borrow.key, right.borrow().key);
                print_helper(right);
            }
        }

        if let Some(ref root) = self.root_node {
            println!(\"digraph {{\\n  ordering = out;\");
            print_helper(root);
            println!(\"}}\");
        }
    }
}

pub fn bostree_node_weak_ref(node: &Rc<RefCell<BOSNode>>) -> Rc<RefCell<BOSNode>> {
    let mut node_mut = node.borrow_mut();
    assert!(node_mut.weak_ref_count < 127);
    assert!(node_mut.weak_ref_count > 0);
    node_mut.weak_ref_count += 1;
    node.clone()
}

pub fn bostree_next_node(node: &Rc<RefCell<BOSNode>>) -> Option<Rc<RefCell<BOSNode>>> {
    if let Some(ref right) = node.borrow().right_child_node {
        let mut current = right.clone();
        loop {
            let next = current.borrow().left_child_node.clone();
            if let Some(n) = next {
                current = n;
            } else {
                break;
            }
        }
        Some(current)
    } else {
        let mut current = node.clone();
        loop {
            let parent = current.borrow().parent_node.as_ref().and_then(|w| w.upgrade());
            if let Some(ref p) = parent {
                if p.borrow().right_child_node.as_ref().map_or(false, |n| Rc::ptr_eq(n, &current)) {
                    current = p.clone();
                    continue;
                }
                return Some(p.clone());
            } else {
                return None;
            }
        }
    }
}

pub fn bostree_previous_node(node: &Rc<RefCell<BOSNode>>) -> Option<Rc<RefCell<BOSNode>>> {
    if let Some(ref left) = node.borrow().left_child_node {
        let mut current = left.clone();
        loop {
            let next = current.borrow().right_child_node.clone();
            if let Some(n) = next {
                current = n;
            } else {
                break;
            }
        }
        Some(current)
    } else {
        let mut current = node.clone();
        loop {
            let parent = current.borrow().parent_node.as_ref().and_then(|w| w.upgrade());
            if let Some(ref p) = parent {
                if p.borrow().left_child_node.as_ref().map_or(false, |n| Rc::ptr_eq(n, &current)) {
                    current = p.clone();
                    continue;
                }
                return Some(p.clone());
            } else {
                return None;
            }
        }
    }
}

pub fn bostree_rank(node: &Rc<RefCell<BOSNode>>) -> u32 {
    let mut counter = node.borrow().left_child_count;
    let mut current = node.clone();
    loop {
        let parent = current.borrow().parent_node.as_ref().and_then(|w| w.upgrade());
        if let Some(ref p) = parent {
            if p.borrow().right_child_node.as_ref().map_or(false, |n| Rc::ptr_eq(n, &current)) {
                counter += 1 + p.borrow().left_child_count;
            }
            current = p.clone();
        } else {
            break;
        }
    }
    counter
}
