    pub fn bostree_node_weak_unref(
        &mut self,
        node: &Rc<RefCell<BOSNode>>,
    ) -> Option<Rc<RefCell<BOSNode>>> {
        let mut node_mut = node.borrow_mut();
        node_mut.weak_ref_count -= 1;
        if node_mut.weak_ref_count == 0 {
            if let Some(ref free_func) = self.free_function {
                free_func(node);
            }
            None
        } else if node_mut.weak_ref_node_valid != 0 {
            Some(node.clone())
        } else {
            None
        }
    }

    pub fn bostree_lookup(&self, key: &str) -> Option<Rc<RefCell<BOSNode>>> {
        let mut node = self.root_node.clone();
        while let Some(current) = node {
            let cmp = {
                let cur_borrow = current.borrow();
                (self.cmp_function)(key, &cur_borrow.key)
            };
            if cmp == 0 {
                return Some(current);
            } else if cmp < 0 {
                let next = current.borrow().left_child_node.clone();
                node = next;
            } else {
                let next = current.borrow().right_child_node.clone();
                node = next;
            }
        }
        None
    }

    pub fn bostree_select(&self, mut index: u32) -> Option<Rc<RefCell<BOSNode>>> {
        let mut node = self.root_node.clone();
        while let Some(current) = node {
            let left_count = current.borrow().left_child_count;
            if left_count <= index {
                index -= left_count;
                if index == 0 {
                    return Some(current);
                }
                index -= 1;
                let next = current.borrow().right_child_node.clone();
                node = next;
            } else {
                let next = current.borrow().left_child_node.clone();
                node = next;
            }
        }
        None
    }

