pub fn bostree_next_node(node: &Rc<RefCell<BOSNode>>) -> Option<Rc<RefCell<BOSNode>>> {
    if let Some(ref right) = node.borrow().right_child_node {
        let mut current = right.clone();
        loop {
            let next = current.borrow().left_child_node.clone();
            if let Some(n) = next {
                current = n;
            } else {
                break;
            }
        }
        Some(current)
    } else {
        let mut current = node.clone();
        loop {
            let parent = current.borrow().parent_node.as_ref().and_then(|w| w.upgrade());
            if let Some(ref p) = parent {
                if p.borrow().right_child_node.as_ref().map_or(false, |n| Rc::ptr_eq(n, &current)) {
                    current = p.clone();
                    continue;
                }
                return Some(p.clone());
            } else {
                return None;
            }
        }
    }
}

pub fn bostree_previous_node(node: &Rc<RefCell<BOSNode>>) -> Option<Rc<RefCell<BOSNode>>> {
