        p_mut.right_child_count = r_left_count;
        if let Some(ref child) = p_mut.right_child_node {
            child.borrow_mut().parent_node = Some(Rc::downgrade(p));
        }
        let ld = p_mut.left_child_node.as_ref().map_or(0, |n| n.borrow().depth + 1);
        let rd = p_mut.right_child_node.as_ref().map_or(0, |n| n.borrow().depth + 1);
        p_mut.depth = imax(ld, rd);
        p_mut.parent_node = Some(Rc::downgrade(&r));
    }

    {
        let mut r_mut = r.borrow_mut();
        r_mut.left_child_node = Some(p.clone());
        let p_borrow = p.borrow();
        r_mut.left_child_count = p_borrow.left_child_count + p_borrow.right_child_count + 1;
        let ld = r_mut.left_child_node.as_ref().map_or(0, |n| n.borrow().depth + 1);
        let rd = r_mut.right_child_node.as_ref().map_or(0, |n| n.borrow().depth + 1);
        r_mut.depth = imax(ld, rd);
    }

    r
}

fn update_depth(node: &Rc<RefCell<BOSNode>>) {
    let ld = node.borrow().left_child_node.as_ref().map_or(0, |n| n.borrow().depth + 1);
    let rd = node.borrow().right_child_node.as_ref().map_or(0, |n| n.borrow().depth + 1);
    node.borrow_mut().depth = imax(ld, rd);
}

impl BOSTree {
    pub fn bostree_new(
        cmp_function: BOSTreeCmpFunction,
        free_function: Option<BOSTreeFreeFunction>,
    ) -> Self {
        BOSTree {
            root_node: None,
            cmp_function,
            free_function,
        }
    }

    pub fn bostree_node_count(&self) -> u32 {
        match &self.root_node {
            Some(root) => {
                let root = root.borrow();
                root.left_child_count + root.right_child_count + 1
            }
            None => 0,
        }
    }

    pub fn bostree_insert(&mut self, key: String, data: Option<String>) -> Rc<RefCell<BOSNode>> {
        let mut node_ptr: Option<Rc<RefCell<BOSNode>>> = self.root_node.clone();
        let mut parent_node: Option<Rc<RefCell<BOSNode>>> = None;

        while let Some(ref current) = node_ptr {
            parent_node = Some(current.clone());
            let cmp = {
                let cur_borrow = current.borrow();
                (self.cmp_function)(&key, &cur_borrow.key)
            };
            if cmp < 0 {
                current.borrow_mut().left_child_count += 1;
                let next = current.borrow().left_child_node.clone();
                node_ptr = next;
            } else {
                current.borrow_mut().right_child_count += 1;
                let next = current.borrow().right_child_node.clone();
                node_ptr = next;
            }
        }

        let new_node = Rc::new(RefCell::new(BOSNode {
            left_child_count: 0,
            right_child_count: 0,
            depth: 0,
            left_child_node: None,
            right_child_node: None,
            parent_node: parent_node.as_ref().map(|p| Rc::downgrade(p)),
            key,
            data,
            weak_ref_count: 1,
            weak_ref_node_valid: 1,
        }));

        if let Some(ref parent) = parent_node {
            let mut parent_mut = parent.borrow_mut();
            let cmp = (self.cmp_function)(&new_node.borrow().key, &parent_mut.key);
            if cmp < 0 {
                parent_mut.left_child_node = Some(new_node.clone());
            } else {
                parent_mut.right_child_node = Some(new_node.clone());
            }
            drop(parent_mut);
        } else {
            self.root_node = Some(new_node.clone());
            return new_node;
        }

        let parent = parent_node.unwrap();
        let depth_changed = {
            let par = parent.borrow();
            let left_ex = par.left_child_node.is_some();
            let right_ex = par.right_child_node.is_some();
            left_ex ^ right_ex
        };
        if depth_changed {
            parent.borrow_mut().depth += 1;
            let mut current = parent.clone();
            loop {
                let cp_opt = {
                    let cur_borrow = current.borrow();
                    cur_borrow.parent_node.as_ref().and_then(|w| w.upgrade())
                };
                if let Some(ref cp) = cp_opt {
                    let (new_left_depth, new_right_depth) = {
                        let cp_borrow = cp.borrow();
                        let ld = cp_borrow.left_child_node.as_ref().map_or(0, |n| n.borrow().depth + 1);
                        let rd = cp_borrow.right_child_node.as_ref().map_or(0, |n| n.borrow().depth + 1);
                        (ld, rd)
                    };
                    let max_depth = imax(new_left_depth, new_right_depth);
                    {
                        let mut cp_mut = cp.borrow_mut();
                        if cp_mut.depth != max_depth {
                            cp_mut.depth = max_depth;
                        } else {
                            break;
                        }
                    }
                    if new_left_depth.wrapping_sub(2) == new_right_depth {
                        let left_cp = cp.borrow().left_child_node.clone().unwrap();
                        let left_balance = balance_node(&*left_cp.borrow());
                        if left_balance > 0 {
                            rotate_left(self, &left_cp);
                        }
                        current = rotate_right(self, cp);
                    } else if new_right_depth.wrapping_sub(2) == new_left_depth {
                        let right_cp = cp.borrow().right_child_node.clone().unwrap();
                        let right_balance = balance_node(&*right_cp.borrow());
                        if right_balance < 0 {
                            rotate_right(self, &right_cp);
                        }
                        current = rotate_left(self, cp);
                    } else {
                        current = cp.clone();
                    }
                } else {
                    break;
                }
            }
        }

        new_node
    }

    pub fn bostree_remove(&mut self, node: &Rc<RefCell<BOSNode>>) {
        let mut bubble_up: Option<Rc<RefCell<BOSNode>>> = None;

        let has_two_children = {
            let n = node.borrow();
            n.left_child_node.is_some() && n.right_child_node.is_some()
        };

        if has_two_children {
            let (candidate, lost_child) = {
                let node_borrow = node.borrow();
                let left_depth = node_borrow.left_child_node.as_ref().map_or(0, |n| n.borrow().depth);
                let right_depth = node_borrow.right_child_node.as_ref().map_or(0, |n| n.borrow().depth);

                if left_depth >= right_depth {
                    // Find predecessor (rightmost in left subtree)
                    drop(node_borrow);
                    node.borrow_mut().left_child_count -= 1;
                    let mut candidate = node.borrow().left_child_node.clone().unwrap();
                    loop {
                        let next = candidate.borrow().right_child_node.clone();
                        if let Some(n) = next {
                            candidate.borrow_mut().right_child_count -= 1;
                            candidate = n;
                        } else {
                            break;
                        }
                    }
                    let lost = candidate.borrow().left_child_node.clone();
                    (candidate, lost)
                } else {
                    // Find successor (leftmost in right subtree)
                    drop(node_borrow);
                    node.borrow_mut().right_child_count -= 1;
                    let mut candidate = node.borrow().right_child_node.clone().unwrap();
                    loop {
                        let next = candidate.borrow().left_child_node.clone();
                        if let Some(n) = next {
                            candidate.borrow_mut().left_child_count -= 1;
                            candidate = n;
                        } else {
                            break;
                        }
                    }
                    let lost = candidate.borrow().right_child_node.clone();
                    (candidate, lost)
                }
            };

            // bubble_start is candidate's parent before we unlink it
            let bubble_start = candidate.borrow().parent_node.clone().and_then(|w| w.upgrade());

            // Remove candidate from its current position
            if let Some(ref bp) = bubble_start {
                let mut bp_mut = bp.borrow_mut();
                if bp_mut.left_child_node.as_ref().map_or(false, |n| Rc::ptr_eq(n, &candidate)) {
                    bp_mut.left_child_node = lost_child.clone();
                } else {
                    bp_mut.right_child_node = lost_child.clone();
                }
            }
            if let Some(ref lost) = lost_child {
                lost.borrow_mut().parent_node = bubble_start.as_ref().map(|p| Rc::downgrade(p));
            }

            // Anchor candidate into the place where node used to be
            {
                let node_parent = node.borrow().parent_node.clone();
                if let Some(ref parent_weak) = node_parent {
                    if let Some(parent) = parent_weak.upgrade() {
                        let mut parent_mut = parent.borrow_mut();
                        if parent_mut.left_child_node.as_ref().map_or(false, |n| Rc::ptr_eq(n, node)) {
                            parent_mut.left_child_node = Some(candidate.clone());
                        } else {
                            parent_mut.right_child_node = Some(candidate.clone());
                        }
                    }
                } else {
                    self.root_node = Some(candidate.clone());
                }
                candidate.borrow_mut().parent_node = node_parent;
            }

            // Copy children from node to candidate
            {
                let node_borrow = node.borrow();
                let mut cand_mut = candidate.borrow_mut();
                cand_mut.left_child_node = node_borrow.left_child_node.clone();
                cand_mut.left_child_count = node_borrow.left_child_count;
                cand_mut.right_child_node = node_borrow.right_child_node.clone();
                cand_mut.right_child_count = node_borrow.right_child_count;
            }

            if let Some(ref left) = candidate.borrow().left_child_node {
                left.borrow_mut().parent_node = Some(Rc::downgrade(&candidate));
            }
            if let Some(ref right) = candidate.borrow().right_child_node {
                right.borrow_mut().parent_node = Some(Rc::downgrade(&candidate));
            }

            // Rebalance from bubble_start up to candidate (if bubble_start != node)
            if let Some(ref bs) = bubble_start {
                if !Rc::ptr_eq(bs, node) {
                    let mut current = bs.clone();
                    loop {
                        if Rc::ptr_eq(&current, &candidate) {
                            break;
                        }
                        update_depth(&current);
                        {
                            let cur_borrow = current.borrow();
                            let ld = cur_borrow.left_child_node.as_ref().map_or(0, |n| n.borrow().depth + 1);
                            let rd = cur_borrow.right_child_node.as_ref().map_or(0, |n| n.borrow().depth + 1);
                            let balance = (rd as i32) - (ld as i32);
                            if balance > 1 {
                                drop(cur_borrow);
                                let right_child = current.borrow().right_child_node.clone().unwrap();
                                if balance_node(&*right_child.borrow()) < 0 {
                                    rotate_right(self, &right_child);
                                }
                                current = rotate_left(self, &current);
                            } else if balance < -1 {
                                drop(cur_borrow);
                                let left_child = current.borrow().left_child_node.clone().unwrap();
                                if balance_node(&*left_child.borrow()) > 0 {
                                    rotate_left(self, &left_child);
                                }
                                current = rotate_right(self, &current);
                            }
                        }
                        let parent = current.borrow().parent_node.clone().and_then(|w| w.upgrade());
                        if let Some(p) = parent {
                            current = p;
                        } else {
                            break;
                        }
                    }
                }
            }

            // Fix candidate's depth
            update_depth(&candidate);

            // Set bubble_up to parent of candidate
            bubble_up = candidate.borrow().parent_node.clone().and_then(|w| w.upgrade());

            // Decrement child count in bubble_up (candidate's parent)
            if let Some(ref bp) = bubble_up {
                let mut bp_mut = bp.borrow_mut();
                if bp_mut.left_child_node.as_ref().map_or(false, |n| Rc::ptr_eq(n, &candidate)) {
                    bp_mut.left_child_count -= 1;
                } else {
                    bp_mut.right_child_count -= 1;
                }
            }
        } else {
            // Node has at most one child
            let node_parent = node.borrow().parent_node.clone();
            if node_parent.is_none() {
                // Node is root
                if let Some(ref left) = node.borrow().left_child_node {
                    self.root_node = Some(left.clone());
                    left.borrow_mut().parent_node = None;
                } else if let Some(ref right) = node.borrow().right_child_node {
                    self.root_node = Some(right.clone());
                    right.borrow_mut().parent_node = None;
                } else {
                    self.root_node = None;
                }
                bubble_up = None;
            } else {
                // Replace node with its child in parent
                let (candidate, candidate_count) = {
                    let node_borrow = node.borrow();
                    if node_borrow.right_child_node.is_some() {
                        (node_borrow.right_child_node.clone(), node_borrow.right_child_count)
                    } else {
                        (node_borrow.left_child_node.clone(), node_borrow.left_child_count)
                    }
                };

                let parent = node_parent.as_ref().unwrap().upgrade().unwrap();
                {
                    let mut parent_mut = parent.borrow_mut();
                    if parent_mut.left_child_node.as_ref().map_or(false, |n| Rc::ptr_eq(n, node)) {
                        parent_mut.left_child_node = candidate.clone();
                        parent_mut.left_child_count = candidate_count;
                    } else {
                        parent_mut.right_child_node = candidate.clone();
                        parent_mut.right_child_count = candidate_count;
                    }
                }
                if let Some(ref cand) = candidate {
                    cand.borrow_mut().parent_node = Some(Rc::downgrade(&parent));
                }
                bubble_up = Some(parent.clone());
            }
        }

        // Rebalance up to root
        self.rebalance_after_remove(bubble_up);

        node.borrow_mut().weak_ref_node_valid = 0;
        self.do_weak_unref(node);
    }

    fn rebalance_after_remove(&mut self, mut bubble_up: Option<Rc<RefCell<BOSNode>>>) {
        let mut bubbling_finished = false;
        while let Some(mut current) = bubble_up.take() {
            if !bubbling_finished {
                // Calculate updated depth
                let (left_depth, right_depth) = {
                    let cur_borrow = current.borrow();
                    let ld = cur_borrow.left_child_node.as_ref().map_or(0, |n| n.borrow().depth + 1);
                    let rd = cur_borrow.right_child_node.as_ref().map_or(0, |n| n.borrow().depth + 1);
                    (ld, rd)
                };
                let new_depth = imax(left_depth, right_depth);
                let depth_changed = {
                    let mut cur_mut = current.borrow_mut();
                    let changed = cur_mut.depth != new_depth;
                    cur_mut.depth = new_depth;
                    changed
                };

                let balance = (right_depth as i32) - (left_depth as i32);

                if balance < -1 {
                    let left_child = current.borrow().left_child_node.clone().unwrap();
                    let left_balance = balance_node(&*left_child.borrow());
                    if left_balance > 0 {
                        rotate_left(self, &left_child);
                    }
                    current = rotate_right(self, &current);
                } else if balance > 1 {
                    let right_child = current.borrow().right_child_node.clone().unwrap();
                    let right_balance = balance_node(&*right_child.borrow());
                    if right_balance < 0 {
                        rotate_right(self, &right_child);
                    }
                    current = rotate_left(self, &current);
                } else {
                    if !depth_changed {
                        bubbling_finished = true;
                    }
                }
            }

            // Decrement child count in parent of current
            if let Some(ref parent_node) = current.borrow().parent_node.clone().and_then(|w| w.upgrade()) {
                let mut pm = parent_node.borrow_mut();
                if pm.left_child_node.as_ref().map_or(false, |n| Rc::ptr_eq(n, &current)) {
                    pm.left_child_count -= 1;
                } else {
                    pm.right_child_count -= 1;
                }
                bubble_up = Some(parent_node.clone());
            } else {
                bubble_up = None;
            }
        }
    }

    fn do_weak_unref(&mut self, node: &Rc<RefCell<BOSNode>>) {
        let weak_ref_count = {
            let mut node_mut = node.borrow_mut();
            node_mut.weak_ref_count -= 1;
            node_mut.weak_ref_count
        };
        if weak_ref_count == 0 {
            if let Some(ref free_func) = self.free_function {
                free_func(node);
            }
        }
    }

    pub fn bostree_node_weak_unref(
        &mut self,
        node: &Rc<RefCell<BOSNode>>,
    ) -> Option<Rc<RefCell<BOSNode>>> {
        let (weak_ref_count, weak_ref_node_valid) = {
            let mut node_mut = node.borrow_mut();
            node_mut.weak_ref_count -= 1;
            (node_mut.weak_ref_count, node_mut.weak_ref_node_valid)
        };
        if weak_ref_count == 0 {
            if let Some(ref free_func) = self.free_function {
                free_func(node);
            }
            None
        } else if weak_ref_node_valid != 0 {
            Some(node.clone())
        } else {
            None
        }
    }

    pub fn bostree_lookup(&self, key: &str) -> Option<Rc<RefCell<BOSNode>>> {
        let mut node = self.root_node.clone();
        while let Some(current) = node {
            let cmp = {
                let cur_borrow = current.borrow();
                (self.cmp_function)(key, &cur_borrow.key)
            };
            if cmp == 0 {
                return Some(current);
            } else if cmp < 0 {
                let next = current.borrow().left_child_node.clone();
                node = next;
            } else {
                let next = current.borrow().right_child_node.clone();
                node = next;
            }
        }
        None
    }

    pub fn bostree_select(&self, mut index: u32) -> Option<Rc<RefCell<BOSNode>>> {
        let mut node = self.root_node.clone();
        while let Some(current) = node {
            let left_count = current.borrow().left_child_count;
            if left_count <= index {
                index -= left_count;
                if index == 0 {
                    return Some(current);
                }
                index -= 1;
                let next = current.borrow().right_child_node.clone();
                node = next;
            } else {
                let next = current.borrow().left_child_node.clone();
                node = next;
            }
        }
        None
    }

    #[cfg(debug_assertions)]
    pub fn bostree_print(&self) {
        fn print_helper(node: &Rc<RefCell<BOSNode>>) {
            let node_borrow = node.borrow();
            println!(
                "  {} [label=\"N ({},{},{})\"];",
                node_borrow.key,
                node_borrow.left_child_count,
                node_borrow.right_child_count,
                node_borrow.depth
            );
            if let Some(ref parent_weak) = node_borrow.parent_node {
                if let Some(parent) = parent_weak.upgrade() {
                    println!(
                        "  {} -> {} [color=green];",
                        node_borrow.key,
                        parent.borrow().key
                    );
                }
            }
            if let Some(ref left) = node_borrow.left_child_node {
                println!("  {} -> {}", node_borrow.key, left.borrow().key);
                print_helper(left);
            }
            if let Some(ref right) = node_borrow.right_child_node {
                println!("  {} -> {}", node_borrow.key, right.borrow().key);
                print_helper(right);
            }
        }

        if let Some(ref root) = self.root_node {
            println!("digraph {{\n  ordering = out;");
            print_helper(root);
            println!("}}");
        }
    }
}

pub fn bostree_node_weak_ref(node: &Rc<RefCell<BOSNode>>) -> Rc<RefCell<BOSNode>> {
    let mut node_mut = node.borrow_mut();
    assert!(node_mut.weak_ref_count < 127);
    assert!(node_mut.weak_ref_count > 0);
    node_mut.weak_ref_count += 1;
    node.clone()
}

pub fn bostree_next_node(node: &Rc<RefCell<BOSNode>>) -> Option<Rc<RefCell<BOSNode>>> {
    if let Some(ref right) = node.borrow().right_child_node {
        let mut current = right.clone();
        loop {
            let next = current.borrow().left_child_node.clone();
            if let Some(n) = next {
                current = n;
            } else {
                break;
            }
        }
        Some(current)
    } else {
        let mut current = node.clone();
        loop {
            let parent = current.borrow().parent_node.as_ref().and_then(|w| w.upgrade());
            if let Some(ref p) = parent {
                if p.borrow().right_child_node.as_ref().map_or(false, |n| Rc::ptr_eq(n, &current)) {
                    current = p.clone();
                    continue;
                }
                return Some(p.clone());
            } else {
                return None;
            }
        }
    }
}

pub fn bostree_previous_node(node: &Rc<RefCell<BOSNode>>) -> Option<Rc<RefCell<BOSNode>>> {
    if let Some(ref left) = node.borrow().left_child_node {
        let mut current = left.clone();
        loop {
            let next = current.borrow().right_child_node.clone();
            if let Some(n) = next {
                current = n;
            } else {
                break;
            }
        }
        Some(current)
    } else {
        let mut current = node.clone();
        loop {
            let parent = current.borrow().parent_node.as_ref().and_then(|w| w.upgrade());
            if let Some(ref p) = parent {
                if p.borrow().left_child_node.as_ref().map_or(false, |n| Rc::ptr_eq(n, &current)) {
                    current = p.clone();
                    continue;
                }
                return Some(p.clone());
            } else {
                return None;
            }
        }
    }
}

pub fn bostree_rank(node: &Rc<RefCell<BOSNode>>) -> u32 {
    let mut counter = node.borrow().left_child_count;
    let mut current = node.clone();
    loop {
        let parent = current.borrow().parent_node.as_ref().and_then(|w| w.upgrade());
        if let Some(ref p) = parent {
            if p.borrow().right_child_node.as_ref().map_or(false, |n| Rc::ptr_eq(n, &current)) {
                counter += 1 + p.borrow().left_child_count;
            }
            current = p.clone();
        } else {
            break;
        }
    }
    counter
}
